以下の Supabase スキーマ設計を品質検査してください:

```sql
create type public.order_status as enum ('pending', 'confirmed', 'shipped', 'delivered', 'cancelled');

create table public.users (
  id uuid primary key default gen_random_uuid(),
  email text not null unique,
  name text not null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  deleted_at timestamptz,
  metadata jsonb default '{}'::jsonb
);

alter table public.users enable row level security;
create policy "users_select_own" on public.users for select using (auth.uid() = id);

create table public.orders (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references public.users(id),
  total_amount numeric(10,2) not null check (total_amount >= 0),
  status public.order_status not null default 'pending',
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  deleted_at timestamptz,
  metadata jsonb default '{}'::jsonb
);

alter table public.orders enable row level security;
create policy "orders_select_own" on public.orders for select using (auth.uid() = user_id);

create index idx_orders_user_id on public.orders(user_id);
create index idx_orders_status on public.orders(status);

create or replace function public.update_updated_at()
returns trigger as $$
begin
  new.updated_at = now();
  return new;
end;
$$ language plpgsql;

create trigger set_updated_at_users before update on public.users for each row execute function public.update_updated_at();
create trigger set_updated_at_orders before update on public.orders for each row execute function public.update_updated_at();
```
